SourceCode.Declaration:
/// <summary>
/// Extension class for the puechaseorder form data source.
/// Controls the visibility of the "CreateLinkNew" button based on the purch status.
/// The button is visible only if the Purchase order has been invoiced.
/// </summary>
[ExtensionOf(formDataSourceStr(PurchTable, PurchTable))]
final class ETGPutchTableformDataSourceStr_Extension
{
}

Method.Source:
public int active()
{               
    int ret = next active();

    if(ETGACFParameters::find().EnableUATSmallPoints)
    {
        PurchTable purchTable = this.cursor();
        FormRun    formRun    = this.formRun();
        if (formRun && purchTable)
        {
            FormButtonControl createlinkInvoice = this.formRun().design().controlName(formControlStr(PurchTable, CreateLinkNew)) as FormButtonControl;

            if (purchTable.PurchStatus == PurchStatus::Invoiced)
            {
                createlinkInvoice.visible(true);
            }
            else
            {
                createlinkInvoice.visible(false);
            }
        }
    }
    return ret;
}
